module serial2parallel (
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg [7:0]dout_parallel,
    output reg dout_valid
);

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin

        cnt <= 4'd0;
        dout_parallel <= 8'd0;
    end else begin

        dout_valid <= 1'b0;

        if ((cnt < 4'd8) && din_valid) begin
            dout_parallel[cnt] <= din_serial;
        end

        if (cnt == 4'd8) begin
            dout_valid <= 1'b1;
        end
    end
end

always @(posedge clk) begin

    if (cnt > 4'd8) begin
        cnt <= 4'd0;
    end
end

reg [3:0] cnt;
endmodule
